# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, jsonify, session
app = Flask(__name__)
app.secret_key = 'your secret key here'  # Replace with your own secret key

@app.route('/update_profile', methods=['POST'])
def update_profile():
    data = request.get_json()
    
    if 'email' in data:
        session['email'] = data['email']  # Update email in session
        
    if 'password' in data:
        session['password'] = data['password']  # Update password in session
        
    if '2fa_settings' in data:
        session['2fa_settings'] = data['2fa_settings']  # Update 2FA settings in session
    
    return jsonify({"message": "Profile updated successfully."}), 201